const newItems = [];

for (const item of $input.all()) {
  // 确保数据路径正确，防止报错
  const delivery = item.json.data && item.json.data.delivery ? item.json.data.delivery : null;
   let orderDetails=delivery.details.map(el=>{
    return {
      sku_code:el.sku_code,
      sku_name:el.sku_name,
      quantity:el.qty,
      price:el.price,
      amount:el.amount
    }
  })

  if (delivery) {

    // 1. 获取 delivery_date 
    // 注意：根据你的JSON，这个字段在 delivery_statusInfo 对象下
    let deliveryDate = null;
    if (delivery.delivery_statusInfo) {
      deliveryDate = delivery.delivery_statusInfo.delivery_date;
    }

    // 2. 准备订单层级的公共数据
    const baseInfo = {
      platform_code: delivery.platform_code,
      express_no: delivery.express_no,
      shop: delivery.shop_name,
      customer_name: delivery.vip_name,
      delivery_date: deliveryDate  // <--- 新增字段
    };

    // 3. 遍历商品详情 details
    if (delivery.details && Array.isArray(delivery.details)) {
      for (const detail of delivery.details) {

        const skuCode = detail.sku_code;
        const skuName=detail.sku_name

        // 4. 遍历唯一码 detail_unique
        if (detail.detail_unique && Array.isArray(detail.detail_unique)) {
          for (const uniqueItem of detail.detail_unique) {

            // 5. 组合最终数据并推入数组
            newItems.push({
              json: {
                ...baseInfo,             // 展开公共字段 (含 delivery_date)
                sku_code: skuCode,       // SKU编码
                sku_name:skuName,
                unique_code: uniqueItem.unique_code,// 唯一码
                watch_type:detail.item_code, //机型
                warehouse_name:uniqueItem.warehouse_name,
                order_details:orderDetails, //订单详情
                payment:delivery.payment,
                price:detail.price
              }
            });

          }
        }
      }
    }
  }
}

return newItems;

